// ============================================================
// ChannelConfigService v2 — Validation + Normalisation
// ============================================================
// Phase 5 : Ajout validation tenant_id obligatoire
// ============================================================

const items = $input.all();

const VALID_ACTIONS = [
  'GET_CONFIG',
  'GET_CONFIG_BY_CHANNEL',
  'VALIDATE_CHANNEL',
  'LIST_ALL',
];

function fail(idx, msg) {
  throw new Error(`ChannelConfigService — Item[${idx}] ${msg}`);
}

return items.map((it, idx) => {
  const input = it.json || {};
  const action = String(input.action || '').trim().toUpperCase();

  if (!action) fail(idx, 'champ obligatoire manquant: action');
  if (!VALID_ACTIONS.includes(action)) {
    fail(idx, `action inconnue: '${action}'. Valides: ${VALID_ACTIONS.join(', ')}`);
  }

  if (input.tenant_id === undefined || input.tenant_id === null || String(input.tenant_id).trim() === '') {
    fail(idx, 'champ obligatoire manquant: tenant_id');
  }

    if (action === 'GET_CONFIG') {
    if (!input.config_id) fail(idx, 'GET_CONFIG — champ obligatoire manquant: config_id');
  }

  if (action === 'GET_CONFIG_BY_CHANNEL') {
    const missing = [];
    if (!input.channel_name) missing.push('channel_name');
    if (!input.diffusion_type) missing.push('diffusion_type');
    if (missing.length) {
      fail(idx, `GET_CONFIG_BY_CHANNEL — champs obligatoires manquants: ${missing.join(', ')}`);
    }
  }

  if (action === 'VALIDATE_CHANNEL') {
    if (!input.channel_name) fail(idx, 'VALIDATE_CHANNEL — champ obligatoire manquant: channel_name');
  }

  const normalized = { ...input, action };
  if (normalized.channel_name) normalized.channel_name = String(normalized.channel_name).trim().toUpperCase();
  if (normalized.diffusion_type) normalized.diffusion_type = String(normalized.diffusion_type).trim().toUpperCase();
  if (normalized.config_id) normalized.config_id = String(normalized.config_id).trim().toUpperCase();

  return {
    json: normalized,
    pairedItem: it.pairedItem ?? { item: idx },
  };
});

// ============================================================
// ChannelConfigService v2 — Cache + PostgreSQL Fallback
// ============================================================
// REMPLACEMENT des 4 nœuds Airtable par 1 seul nœud intelligent.
//
// Stratégie :
//   1. Charger toutes les configs en mémoire (staticData)
//   2. TTL de 5 minutes avant rafraîchissement
//   3. Si le cache est vide → flag pour charger depuis PostgreSQL
//
// Pourquoi :
//   - channel_config = 6 lignes, quasi-statique
//   - Économise 4 requêtes BDD par exécution
//   - Latence quasi-nulle (mémoire vs réseau)
// ============================================================

const staticData = $getWorkflowStaticData('global');
const CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
const now = Date.now();

// Vérifier si le cache est valide
let configs = staticData._channelConfigs || null;
const cacheTime = staticData._channelConfigsCachedAt || 0;
const cacheValid = configs && configs.length > 0 && (now - cacheTime) < CACHE_TTL_MS;

if (cacheValid) {
  // Cache hit → on passe directement au routeur avec le flag
  return $input.all().map(it => ({
    json: {
      ...it.json,
      _cache_hit: true,
      _configs: configs,
    },
    pairedItem: it.pairedItem,
  }));
} else {
  // Cache miss → marquer pour chargement PostgreSQL
  return $input.all().map(it => ({
    json: {
      ...it.json,
      _cache_hit: false,
      _configs: null,
    },
    pairedItem: it.pairedItem,
  }));
}

// ============================================================
// Mise à jour du cache + Reattacher les requêtes originales
// ============================================================
// On stocke les résultats PostgreSQL dans staticData
// puis on les attache à chaque requête pour le routeur d'actions.
// ============================================================

const staticData = $getWorkflowStaticData('global');
const pgResults = $input.all();

// Transformer les résultats PostgreSQL en configs propres
const configs = pgResults
  .map(r => r.json)
  .filter(r => r.config_id) // ignorer les lignes vides
  .map(r => ({
    config_id: r.config_id,
    channel_name: r.channel_name || '',
    diffusion_type: r.diffusion_type || '',
    post_type: r.post_type || '',
    text_max_chars: r.text_max_chars ?? null,
    headline_max_chars: r.headline_max_chars ?? null,
    description_max_chars: r.description_max_chars ?? null,
    hashtags_recommended: r.hashtags_recommended ?? 0,
    media_required: r.media_required || false,
    native_scheduling: r.native_scheduling || false,
    tone_default: r.tone_default || '',
    typical_api_calls: r.typical_api_calls ?? 1,
  }));

// Mettre en cache
staticData._channelConfigs = configs;
staticData._channelConfigsCachedAt = Date.now();

// Récupérer les requêtes originales et y attacher les configs
const originalRequests = $items('Valider entrée & action');

return originalRequests.map((it, idx) => ({
  json: {
    ...it.json,
    _cache_hit: true, // maintenant on a les données
    _configs: configs,
  },
  pairedItem: { item: idx },
}));

// ============================================================
// Routeur d'Actions Unifié — Traitement en mémoire
// ============================================================
// REMPLACEMENT des 4 branches (Airtable + Réponse) par 1 seul nœud.
//
// Toutes les données sont en mémoire (_configs).
// On route par action et on construit la réponse directement.
//
// Avantage vs. v1 :
//   - 1 nœud au lieu de 8 (4 Airtable + 4 Réponse)
//   - 0 requête réseau (tout en mémoire)
//   - Code plus lisible et maintenable
//   - Plus de problèmes de pairedItem avec Airtable
// ============================================================

const items = $input.all();

return items.map((it, idx) => {
  const req = it.json;
  const action = req.action;
  const configs = req._configs || [];
  const norm = (v) => String(v || '').trim().toUpperCase();

  // Nettoyer les champs internes avant la réponse
  const cleanReq = { ...req };
  delete cleanReq._cache_hit;
  delete cleanReq._configs;

  // ─── GET_CONFIG ───
  if (action === 'GET_CONFIG') {
    const configId = norm(req.config_id);
    const found = configs.find(c => norm(c.config_id) === configId);

    if (!found) {
      return {
        json: {
          success: false,
          action: 'GET_CONFIG',
          config_id: req.config_id,
          error_code: 'CONFIG_NOT_FOUND',
          error_message: `Aucune configuration trouvée pour config_id: ${req.config_id}`,
        },
        pairedItem: { item: idx },
      };
    }

    return {
      json: {
        success: true,
        action: 'GET_CONFIG',
        config: { ...found },
      },
      pairedItem: { item: idx },
    };
  }

  // ─── GET_CONFIG_BY_CHANNEL ───
  if (action === 'GET_CONFIG_BY_CHANNEL') {
    const ch = norm(req.channel_name);
    const dt = norm(req.diffusion_type);
    const matches = configs.filter(c => norm(c.channel_name) === ch && norm(c.diffusion_type) === dt);

    if (matches.length === 0) {
      return {
        json: {
          success: false,
          action: 'GET_CONFIG_BY_CHANNEL',
          channel_name: req.channel_name,
          diffusion_type: req.diffusion_type,
          error_code: 'CONFIG_NOT_FOUND',
          error_message: `Aucune configuration pour ${req.channel_name} / ${req.diffusion_type}`,
        },
        pairedItem: { item: idx },
      };
    }

    return {
      json: {
        success: true,
        action: 'GET_CONFIG_BY_CHANNEL',
        channel_name: req.channel_name,
        diffusion_type: req.diffusion_type,
        count: matches.length,
        configs: matches.map(c => ({ ...c })),
      },
      pairedItem: { item: idx },
    };
  }

  // ─── VALIDATE_CHANNEL ───
  if (action === 'VALIDATE_CHANNEL') {
    const ch = norm(req.channel_name);
    const channelConfigs = configs.filter(c => norm(c.channel_name) === ch);
    const supported = channelConfigs.length > 0;
    const types = supported
      ? [...new Set(channelConfigs.map(c => norm(c.diffusion_type)).filter(Boolean))]
      : [];

    return {
      json: {
        ...cleanReq,
        success: true,
        action: 'VALIDATE_CHANNEL',
        channel_name: req.channel_name,
        supported,
        available_diffusion_types: types,
        config_count: channelConfigs.length,
        error_code: supported ? null : 'UNSUPPORTED_CHANNEL',
        error_message: supported ? null : `Canal non supporté: ${req.channel_name}`,
      },
      pairedItem: { item: idx },
    };
  }

  // ─── LIST_ALL ───
  if (action === 'LIST_ALL') {
    return {
      json: {
        success: true,
        action: 'LIST_ALL',
        count: configs.length,
        configs: configs.map(c => ({ ...c })),
      },
      pairedItem: { item: idx },
    };
  }

  // Fallback (ne devrait jamais arriver grâce à la validation)
  return {
    json: {
      success: false,
      action: action,
      error_code: 'UNKNOWN_ACTION',
      error_message: `Action non gérée: ${action}`,
    },
    pairedItem: { item: idx },
  };
});
